SELECT B.board_id, B.sys_id, B.board_type, B.board_title, B.board_desc, B.status_use_yn, B.board_use_yn, B.reg_dt, S.sys_nm, (SELECT COUNT(*) FROM TB_POST_INFO P WHERE P.board_id = B.board_id AND P.post_status = 'W' AND P.post_use_yn = 'Y') AS ntt_wait, (SELECT COUNT(*) FROM TB_POST_INFO P WHERE P.board_id = B.board_id AND P.post_status = 'R' AND P.post_use_yn = 'Y') AS ntt_rcept, (SELECT COUNT(*) FROM TB_POST_INFO P WHERE P.board_id = B.board_id AND P.post_status = 'C' AND P.post_use_yn = 'Y') AS ntt_compt, ROW_NUMBER() OVER(ORDER BY B.board_id DESC) AS rsn FROM TB_BOARD_INFO B JOIN TB_SYS_INFO S ON B.sys_id = S.sys_id WHERE B.board_use_yn = 'Y'
AND B.sys_id = #{sysId}
AND B.board_type = #{boardType}
AND (B.board_title LIKE '%' + #{keyword} + '%' OR CAST(B.board_id AS VARCHAR) LIKE '%' + #{keyword} + '%')

